import React, { useRef, useState, useEffect } from 'react';
import './App.css';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Lenis from '@studio-freight/lenis'
import { RingLoader } from 'react-spinners'; // Removed PropagateLoader since it's not used
import GradientWrapper from './GradientWrapper';
import { faAngleDown } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Navbar from './components/Navbar';
import FirstSection from './components/FirstSection';
import SecondSection from './components/SecondSection';
import ThirdSection from './components/ThirdSection';
import FourthSection from './components/FourthSection';
import ButtonsHolder from './components/ButtonsHolder';
import Title from './components/Title';

function App() {
  const [loading, setLoading] = useState(true);
  const lenisRef = useRef(null);
  const sectionsRef = useRef([]);

  // ... (rest of the code)

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 2500);

    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    lenisRef.current = new Lenis();

    lenisRef.current.on('scroll', (e) => {
      // Scroll snapping logic
      const sectionPositions = sectionsRef.current.map(
        (section) => section.offsetTop
      );
      const currentScroll = e.scrollY;

      // Find the nearest section to the current scroll position
      const nearestSectionIndex = sectionPositions.reduce(
        (acc, curr, index) =>
          Math.abs(curr - currentScroll) < Math.abs(sectionPositions[acc] - currentScroll)
            ? index
            : acc,
        0
      );

      // Snap to the nearest section
      lenisRef.current.scrollTo(sectionPositions[nearestSectionIndex]);
    });

    // Start the RAF loop for Lenis
    function raf(time) {
      lenisRef.current.raf(time);
      requestAnimationFrame(raf);
    }
    requestAnimationFrame(raf);

    // Initialize AOS
    AOS.init();

    return () => {
      lenisRef.current.destroy();
    };
  }, []);

  // ... (rest of the code)

  return (
    <div className="App">
      {/* ... (rest of the code) */}

      {!loading && (
        <>
          <Navbar />
          <GradientWrapper />
          <div className="rowmenucontainer">
            {/* ... (rest of the code) */}
          </div>
          <div className="sections">
            {/* Add ref to each section */}
            <div ref={(ref) => (sectionsRef.current[0] = ref)}>
              <FirstSection />
            </div>
            <div ref={(ref) => (sectionsRef.current[1] = ref)}>
              <SecondSection />
            </div>
            <div ref={(ref) => (sectionsRef.current[2] = ref)}>
              <ThirdSection />
            </div>
            <div ref={(ref) => (sectionsRef.current[3] = ref)}>
              <FourthSection />
            </div>
          </div>
        </>
      )}
    </div>
  );
}

export default App;
